mapper.insert:
insert into batch.job_instance ( tenant_id, job_definition_id, trigger_request_id, job_code, instance_no, biz_date, trigger_type, instance_status, batch_no, operator_id, rerun_flag, retry_flag, rerun_reason, related_file_id, parent_instance_id, queue_code, worker_group, priority, dedup_key, run_attempt, job_definition_version, rerun_policy_snapshot, version, expected_partition_count, success_partition_count, failed_partition_count, trace_id, params_snapshot, calendar_code, data_interval_start, data_interval_end, high_water_mark_in, high_water_mark_out, result_summary, deadline_at, expected_duration_seconds, sla_alerted_at, replay_session_id, dry_run ) values ( #{tenantId}, #{jobDefinitionId}, #{triggerRequestId}, #{jobCode}, #{instanceNo}, coalesce(#{bizDate}, CURRENT_DATE), #{triggerType}, #{instanceStatus}, #{batchNo}, #{operatorId}, #{rerunFlag}, #{retryFlag}, #{rerunReason}, #{relatedFileId}, #{parentInstanceId}, #{queueCode}, #{workerGroup}, #{priority}, #{dedupKey}, #{runAttempt}, #{jobDefinitionVersion}, #{rerunPolicySnapshot,jdbcType=VARCHAR}::jsonb, #{version}, #{expectedPartitionCount}, #{successPartitionCount}, #{failedPartitionCount}, #{traceId}, #{paramsSnapshot,jdbcType=VARCHAR}::jsonb, #{calendarCode}, #{dataIntervalStart}, #{dataIntervalEnd}, #{highWaterMarkIn}, #{highWaterMarkOut}, #{resultSummary,jdbcType=VARCHAR}::jsonb, #{deadlineAt}, #{expectedDurationSeconds}, #{slaAlertedAt}, #{replaySessionId},
#{dryRun} false
)

