update batch.job_instance
set instance_status = #{instanceStatus},
    finished_at = coalesce(#{finishedAt}, finished_at),
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and version = #{expectedVersion}

