  from batch.job_instance
 where tenant_id = #{tenantId}
   and job_code = #{jobCode}
   and biz_date = #{bizDate}
   and instance_status not in ('SUCCESS', 'FAILED', 'CANCELLED', 'TERMINATED')

select count(1)
  from batch.job_instance ji
  join batch.job_definition jd
    on jd.tenant_id = ji.tenant_id
   and jd.job_code = ji.job_code
 where ji.tenant_id = #{tenantId}
   and jd.job_group_code = #{jobGroupCode}
   and ji.biz_date = #{bizDate}
   and ji.instance_status not in ('SUCCESS', 'FAILED', 'CANCELLED', 'TERMINATED')

select *
  from batch.job_instance
 where tenant_id = #{tenantId}
   and biz_date between #{bizDateFrom} and #{bizDateTo}

